async function* consumeOpenAIStream(stream: AsyncIterable<any>, signal: AbortSignal | undefined, mapUsage: (u: any) => any = defaultUsage): AsyncGenerator<any> {
  let finishReason: string | null = null;
  for await (const chunk of stream) {
    if (signal?.aborted) throw new Error('Agent stopped by user');
    const choice = chunk.choices?.[0];
    if (choice?.delta?.content) yield { type: 'text', text: choice.delta.content };
    if (choice?.delta?.reasoning_content) yield { type: 'thinking', text: choice.delta.reasoning_content };
    if (choice?.finish_reason) finishReason = choice.finish_reason;
    if (chunk.usage) yield { type: 'done', finishReason: finishReason || 'stop', ...mapUsage(chunk) };
  }
}
VLLM passes a mapUsage that adds costUsd/runnerSessionId; OpenAI and Mistral use the default. Optionally fold MistralProvider into a thin OpenAICompatProvider base shared with VLLMProvider, keeping provider:'mistral' in results.

